    } else if (check.equals(this)) {
        // check for DST overlap (two midnights)
        Date earlier = new Date(date.getTime() - TimeZone.getDefault().getDSTSavings());
        if (earlier.getDate() == dom) {
            date = earlier;
        }
    }
    return date;
}

